JSONcURLPython <pre><code>{
  "model": "gemini-1.5-pro",
  "esforco_de_raciocinio": "alto",
  "verbosidade": "média",
  "max_tokens": 4000,
  "temperature": 0.7,
  "description": "Para tarefas agênticas complexas com múltiplas etapas"
}
</code></pre> <pre><code>curl -X POST "https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-pro:generateContent" \
-H "Content-Type: application/json" \
-H "x-goog-api-key: $GEMINI_API_KEY" \
-d '{
  "contents": [{
    "parts": [{"text": "sua_consulta_aqui"}]
  }],
  "generationConfig": {
    "maxOutputTokens": 4000,
    "temperature": 0.7,
    "topP": 0.9
  },
  "systemInstruction": {
    "parts": [{"text": "esforco_de_raciocinio: alto\nverbosidade: média"}]
  }
}'
</code></pre> <pre><code>import google.generativeai as genai

genai.configure(api_key="your_api_key")

model = genai.GenerativeModel(
    'gemini-1.5-pro',
    generation_config={
        'max_output_tokens': 4000,
        'temperature': 0.7,
        'top_p': 0.9,
        'top_k': 40
    },
    system_instruction="esforco_de_raciocinio: alto\nverbosidade: média"
)

response = model.generate_content("sua_consulta_aqui")
print(response.text)
</code></pre>

JSONcURLPython <pre><code>{
  "model": "gpt-5",
  "reasoning_effort": "high",
  "verbosity": "medium",
  "max_tokens": 4000,
  "temperature": 0.7,
  "description": "Para tarefas agênticas complexas que requerem múltiplas etapas"
}
</code></pre> <pre><code>curl -X POST "https://api.openai.com/v1/chat/completions" \
-H "Content-Type: application/json" \
-H "Authorization: Bearer $OPENAI_API_KEY" \
-d '{
  "model": "gpt-5",
  "messages": [
    {
      "role": "system", 
      "content": "reasoning_effort: high\nverbosity: medium"
    },
    {
      "role": "user", 
      "content": "sua_consulta_aqui"
    }
  ],
  "max_tokens": 4000,
  "temperature": 0.7
}'
</code></pre> <pre><code>import openai

client = openai.OpenAI(api_key="your_api_key")

response = client.chat.completions.create(
    model="gpt-5",
    messages=[
        {
            "role": "system", 
            "content": "reasoning_effort: high\nverbosity: medium"
        },
        {
            "role": "user", 
            "content": "sua_consulta_aqui"
        }
    ],
    max_tokens=4000,
    temperature=0.7
)

print(response.choices[0].message.content)
</code></pre>

